SELECT c.country_name
FROM countries c
WHERE c.WHO_region = 'Europe' AND c.vaccination_rate > 70 AND c.testing_rate > 2;

SELECT region_name
FROM WHO_regions
ORDER BY region_name;

SELECT AVG(vaccination_rate) AS average_vaccination_rate
FROM countries
WHERE WHO_region = 'Europe';

SELECT COUNT(*) AS total_countries
FROM countries
WHERE WHO_region = 'Europe' AND vaccination_rate > 60 AND testing_rate > 2.0;
